// Primitives: compared by value
Object.is(42, 42)       // true  → dep unchanged, effect skipped
Object.is('a', 'a')     // true  → dep unchanged, effect skipped
Object.is('a', 'b')     // false → dep changed, effect re-runs

// Objects/arrays: compared by reference
const a = { x: 1 };
const b = { x: 1 };
Object.is(a, b)         // false (different object identity!)
Object.is(a, a)         // true  (same reference)

// Consequence: a new object literal in JSX is always a new reference
// useEffect(() => { ... }, [{ x: 1 }]);  // re-runs on every render!

function SearchResults({ query, pageSize }) {
  const [results, setResults] = useState([]);
  const apiBase = useContext(ApiContext);

  useEffect(() => {
    // Uses: query, pageSize, apiBase — all must be deps
    fetch(`${apiBase}/search?q=${query}&limit=${pageSize}`)
      .then(r => r.json())
      .then(setResults);
  }, [query, pageSize, apiBase]); // ✓ complete
}

const API_URL = 'https://api.example.com'; // outside component — never changes

function UserCard({ userId }) {
  const [user, setUser] = useState(null);
  const cacheRef = useRef({});

  useEffect(() => {
    const cached = cacheRef.current[userId]; // ref.current read — not a dep
    if (cached) { setUser(cached); return; }

    fetch(`${API_URL}/users/${userId}`) // API_URL constant — not a dep
      .then(r => r.json())
      .then(data => {
        cacheRef.current[userId] = data; // mutate ref — not a state update
        setUser(data); // setUser is stable — not a dep
      });
  }, [userId]); // only userId is a reactive dep
}

// Re-fetch when userId changes
useEffect(() => {
  fetchUser(userId).then(setUser);
}, [userId]);

// Effect runs on mount (initial value of userId)
// Effect re-runs whenever userId changes
// Effect does NOT re-run for unrelated state changes

// Re-subscribe when channel or format changes
useEffect(() => {
  const sub = subscribe(channel, { format });
  return () => sub.unsubscribe();
}, [channel, format]);

// Effect re-runs if EITHER channel OR format changes
// If only channel changes: old sub cleaned up, new sub created with new channel
// If only format changes: old sub cleaned up, new sub created with new format
// If neither changes: effect skipped entirely

function FilteredList({ items, threshold }) {
  // visible is derived from props — changing items or threshold changes visible
  const visible = items.filter(item => item.score >= threshold);

  useEffect(() => {
    analytics.trackVisibleCount(visible.length);
  }, [visible.length]); // dep is the derived value, not items/threshold directly
}

// However: 'visible' itself (the array) is a new reference every render
// Using [visible] would re-run every render — use [visible.length] or useMemo

// ✗ options is a new object on every parent render
function Parent() {
  return <Chart options={{ color: 'blue', size: 10 }} />;
}

function Chart({ options }) {
  useEffect(() => {
    drawChart(options);
  }, [options]); // re-runs on every parent re-render — options is always new!
}

// Fix A: destructure to primitives
useEffect(() => {
  drawChart({ color, size });
}, [color, size]); // primitives compare by value — stable

// Fix B: useMemo in the parent
const options = useMemo(() => ({ color: 'blue', size: 10 }), []); // stable ref

// ✗ callback is a new function reference on every parent render
function Parent() {
  return <Timer onTick={() => console.log('tick')} />;
}

function Timer({ onTick }) {
  useEffect(() => {
    const id = setInterval(onTick, 1000);
    return () => clearInterval(id);
  }, [onTick]); // re-registers interval on every parent render!
}

// Fix: useCallback in the parent to stabilise the reference
function Parent() {
  const handleTick = useCallback(() => console.log('tick'), []);
  return <Timer onTick={handleTick} />;
}

// ✗ computeUrl is called at render time, result may be unstable
const url = computeUrl(userId, filters); // object — new ref each render
useEffect(() => { fetch(url); }, [url]);

// ✓ computeUrl called inside the effect — no dep needed
useEffect(() => {
  const url = computeUrl(userId, filters);
  fetch(url);
}, [userId, filters]); // primitives or stable values only

// ESLint error: React Hook useEffect has a missing dependency: 'userId'.
// Either include it or remove the dependency array.
useEffect(() => {
  fetchProfile(userId); // userId used but not in deps
}, []);

// Fix: add userId
useEffect(() => {
  fetchProfile(userId);
}, [userId]);

// ESLint warning: The 'user' object makes the dependencies of useEffect
// change on every render. Move it inside useEffect or wrap in useMemo.
useEffect(() => {
  updateProfile(user);
}, [user]); // user is a new object each render — will re-run every time

import { render, waitFor } from '@testing-library/react';

it('re-fetches only when userId changes', async () => {
  const fetchSpy = jest.spyOn(global, 'fetch').mockResolvedValue({
    json: () => Promise.resolve({ name: 'Alice' }),
  });

  const { rerender } = render(<UserCard userId='1' theme='dark' />);
  await waitFor(() => expect(fetchSpy).toHaveBeenCalledTimes(1));

  // theme change: not in deps — effect should NOT re-run
  rerender(<UserCard userId='1' theme='light' />);
  expect(fetchSpy).toHaveBeenCalledTimes(1); // still 1

  // userId change: in deps — effect SHOULD re-run
  rerender(<UserCard userId='2' theme='light' />);
  await waitFor(() => expect(fetchSpy).toHaveBeenCalledTimes(2));
});

function Dashboard({ userId, filters }) {
  // Without memo: queryParams is a new object on every render
  // const queryParams = buildQuery(userId, filters); // ← unstable

  // With useMemo: queryParams reference stable until userId/filters change
  const queryParams = useMemo(
    () => buildQuery(userId, filters),
    [userId, filters]
  );

  useEffect(() => {
    fetchDashboard(queryParams).then(setData);
  }, [queryParams]); // safe — reference only changes when userId/filters change
}

// Equivalent approach: put buildQuery inside the effect
useEffect(() => {
  const queryParams = buildQuery(userId, filters);
  fetchDashboard(queryParams).then(setData);
}, [userId, filters]); // no useMemo needed — primitive deps only

// ✗ One large effect with mixed concerns
useEffect(() => {
  // Re-runs for userId OR theme changes
  fetchUser(userId).then(setUser);
  document.body.className = `theme-${theme}`;
}, [userId, theme]);

// ✓ Two focused effects with correct deps
useEffect(() => {
  fetchUser(userId).then(setUser);
}, [userId]); // re-runs only when userId changes

useEffect(() => {
  document.body.className = `theme-${theme}`;
  return () => { document.body.className = ''; };
}, [theme]); // re-runs only when theme changes

// ✗ Incorrect: using an effect to derive state
function FilteredList({ items, minScore }) {
  const [visible, setVisible] = useState(items);

  useEffect(() => {
    setVisible(items.filter(i => i.score >= minScore));
  }, [items, minScore]);
  // Problem: extra render cycle on every items/minScore change
}

// ✓ Correct: derive directly in render (no effect needed)
function FilteredList({ items, minScore }) {
  const visible = items.filter(i => i.score >= minScore); // render-time
  // No effect, no extra render cycle
}

function SearchBox({ onSelect }) {
  // onSelect may be a new function reference every render
  const onSelectRef = useRef(onSelect);
  // Keep ref current without triggering effect re-runs
  useEffect(() => { onSelectRef.current = onSelect; });

  useEffect(() => {
    const sub = searchStream.subscribe((result) => {
      onSelectRef.current(result); // always calls the latest onSelect
    });
    return () => sub.unsubscribe();
  }, []); // [] — subscribe once; read latest callback via ref
}
